  "inlineSchema": "// Prisma Schema for Footwear Billing System\n// Run: npx prisma migrate dev --name init\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\n// ─── USERS ──────────────────────────────────────────────────────────────────\nmodel User {\n  id           Int      @id @default(autoincrement())\n  name         String\n  email        String   @unique\n  passwordHash String   @map(\"password_hash\")\n  role         UserRole @default(STAFF)\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n\n  invoices Invoice[]\n\n  @@map(\"users\")\n}\n\nenum UserRole {\n  ADMIN\n  STAFF\n}\n\n// ─── CUSTOMERS ───────────────────────────────────────────────────────────────\nmodel Customer {\n  id            Int      @id @default(autoincrement())\n  name          String\n  phone         String   @unique\n  email         String?\n  creditBalance Decimal  @default(0) @map(\"credit_balance\") @db.Decimal(10, 2)\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  invoices Invoice[]\n  payments Payment[]\n\n  @@map(\"customers\")\n}\n\n// ─── PRODUCTS ────────────────────────────────────────────────────────────────\nmodel Product {\n  id          Int      @id @default(autoincrement())\n  name        String\n  brand       String?\n  category    String?\n  gender      String?\n  description String?\n  imageUrl    String?  @map(\"image_url\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  variants Variant[]\n\n  @@map(\"products\")\n}\n\n// ─── VARIANTS (Size-based Stock) ─────────────────────────────────────────────\nmodel Variant {\n  id            Int      @id @default(autoincrement())\n  productId     Int      @map(\"product_id\")\n  size          String // e.g. \"UK 6\", \"UK 7\", \"UK 8\"\n  sku           String   @unique\n  barcode       String?  @unique\n  price         Decimal  @db.Decimal(10, 2)\n  stock         Int      @default(0)\n  lowStockLimit Int      @default(5) @map(\"low_stock_limit\")\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  product      Product       @relation(fields: [productId], references: [id], onDelete: Cascade)\n  invoiceItems InvoiceItem[]\n\n  @@map(\"variants\")\n}\n\n// ─── INVOICES ────────────────────────────────────────────────────────────────\nmodel Invoice {\n  id          Int           @id @default(autoincrement())\n  invoiceNo   String        @unique @map(\"invoice_no\")\n  customerId  Int?          @map(\"customer_id\")\n  userId      Int           @map(\"user_id\")\n  subtotal    Decimal       @db.Decimal(10, 2)\n  cgst        Decimal       @default(0) @db.Decimal(10, 2)\n  sgst        Decimal       @default(0) @db.Decimal(10, 2)\n  igst        Decimal       @default(0) @db.Decimal(10, 2)\n  discount    Decimal       @default(0) @db.Decimal(10, 2)\n  total       Decimal       @db.Decimal(10, 2)\n  paymentMode PaymentMode   @map(\"payment_mode\")\n  status      InvoiceStatus @default(PAID)\n  notes       String?\n  createdAt   DateTime      @default(now()) @map(\"created_at\")\n\n  customer Customer?     @relation(fields: [customerId], references: [id])\n  user     User          @relation(fields: [userId], references: [id])\n  items    InvoiceItem[]\n  payments Payment[]\n\n  @@map(\"invoices\")\n}\n\nenum PaymentMode {\n  CASH\n  UPI\n  CARD\n  UDHAAR\n  MIXED\n}\n\nenum InvoiceStatus {\n  PAID\n  PARTIAL\n  UNPAID\n  CANCELLED\n}\n\n// ─── INVOICE ITEMS ───────────────────────────────────────────────────────────\nmodel InvoiceItem {\n  id             Int     @id @default(autoincrement())\n  invoiceId      Int     @map(\"invoice_id\")\n  variantId      Int?    @map(\"variant_id\")\n  customName     String? @map(\"custom_name\")\n  customCategory String? @map(\"custom_category\")\n  qty            Int\n  unitPrice      Decimal @map(\"unit_price\") @db.Decimal(10, 2)\n  taxRate        Decimal @default(18) @map(\"tax_rate\") @db.Decimal(5, 2)\n  discount       Decimal @default(0) @db.Decimal(10, 2)\n  total          Decimal @db.Decimal(10, 2)\n\n  invoice Invoice  @relation(fields: [invoiceId], references: [id], onDelete: Cascade)\n  variant Variant? @relation(fields: [variantId], references: [id])\n\n  @@map(\"invoice_items\")\n}\n\n// ─── PAYMENTS ────────────────────────────────────────────────────────────────\nmodel Payment {\n  id         Int         @id @default(autoincrement())\n  invoiceId  Int         @map(\"invoice_id\")\n  customerId Int?        @map(\"customer_id\")\n  amount     Decimal     @db.Decimal(10, 2)\n  mode       PaymentMode\n  note       String?\n  createdAt  DateTime    @default(now()) @map(\"created_at\")\n\n  invoice  Invoice   @relation(fields: [invoiceId], references: [id])\n  customer Customer? @relation(fields: [customerId], references: [id])\n\n  @@map(\"payments\")\n}\n\n// ─── EXPENSES ────────────────────────────────────────────────────────────────\nmodel Expense {\n  id        Int      @id @default(autoincrement())\n  category  String // e.g. Rent, Salary, Utility, Stock Purchase\n  amount    Decimal  @db.Decimal(10, 2)\n  note      String?\n  date      DateTime @default(now())\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"expenses\")\n}\n",
